const payload = $json.body ?? $json;
const timezone = String(payload.timezone ?? 'Asia/Seoul');
const message = String(payload.message ?? '').trim();
const parts = Object.fromEntries(new Intl.DateTimeFormat('sv-SE', { timeZone: timezone, year: 'numeric', month: '2-digit', day: '2-digit' }).formatToParts(new Date()).filter((part) => part.type !== 'literal').map((part) => [part.type, part.value]));
const dateLabel = `${parts.year}-${parts.month}-${parts.day}`;
const timeMin = String(payload.timeMin ?? `${dateLabel}T00:00:00+09:00`);
const timeMax = String(payload.timeMax ?? `${dateLabel}T23:59:59+09:00`);
return [{ json: { message, channel: String(payload.channel ?? 'unknown'), session_id: payload.session_id ?? null, user_id: payload.user_id ?? null, timezone, timeMin, timeMax, window_label: String(payload.window_label ?? dateLabel) } }];

const normalize = (event) => {
  const title = event.summary || '제목 없는 일정';
  const allDay = Boolean(event.start?.date) && !event.start?.dateTime;
  const startAt = allDay ? `${event.start?.date}T00:00:00+09:00` : String(event.start?.dateTime || '');
  const endAt = allDay
    ? `${event.end?.date}T00:00:00+09:00`
    : String(event.end?.dateTime || event.start?.dateTime || '');
  return {
    event_id: event.id || '',
    title,
    start_at: startAt,
    end_at: endAt,
    all_day: allDay,
    location: event.location || '',
  };
};
const events = $input.all().map((item) => item.json).filter((event) => event && (event.summary || event.start || event.id));
const formattedEvents = events.map(normalize).filter((event) => event.start_at && event.end_at);
const formatTime = (value) => new Intl.DateTimeFormat('ko-KR', { timeZone: 'Asia/Seoul', hour: '2-digit', minute: '2-digit', hour12: false }).format(new Date(value));
if (!formattedEvents.length) {
  return [{ json: { reply: '오늘 등록된 일정이 없습니다.', action: 'calendar-summary', count: 0, events: [] } }];
}
const lines = formattedEvents.slice(0, 5).map((event) => {
  if (event.all_day) {
    return `종일 ${event.title}`;
  }
  const start = formatTime(event.start_at);
  const end = formatTime(event.end_at);
  return end ? `${start}-${end} ${event.title}` : `${start} ${event.title}`;
});
const extra = formattedEvents.length > 5 ? ` 외 ${formattedEvents.length - 5}건` : '';
return [{ json: { reply: `오늘 일정은 ${lines.join(', ')}${extra}입니다.`, action: 'calendar-summary', count: formattedEvents.length, events: formattedEvents } }];
